import React, { useState } from "react";

function StationForm({ onNewStation = () => {} }) {
  const [name, setName] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!name.trim()) return alert("Введите название станции");

    try {
      const res = await fetch("http://localhost:5050/stations", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: name.trim() })
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Ошибка создания станции");
      onNewStation(data);
      setName("");
    } catch (err) {
      alert(err.message);
    }
  };

  return (
    <div>
      <h3>Добавить станцию</h3>
      <form onSubmit={handleSubmit}>
        <input
          type="text"
          value={name}
          onChange={e => setName(e.target.value)}
          placeholder="Название станции"
          required
        />
        <button type="submit">Создать</button>
      </form>
    </div>
  );
}

export default StationForm;
